export default async function handler(req, res) {
  const headers = req.headers;
  const userAgent = (headers['user-agent'] || "").toLowerCase();
  
  // Aggressive detection to ensure every executor works
  const isRoblox = 
    userAgent.includes('roblox') || 
    userAgent.includes('rbx') || 
    userAgent.includes('wininet') || 
    headers['roblox-id'] || 
    headers['x-roblox-test'];

  // 1. WEBHOOK PROTECTION (Secretly sends to Discord)
  const DISCORD_WEBHOOK = process.env.DISCORD_WEBHOOK;

  if (req.method === 'POST') {
    try {
      const data = req.body;
      await fetch(DISCORD_WEBHOOK, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          embeds: [{
            title: "✦ HOUR HUB v21.0 Execution",
            color: 0x5B8CFF,
            fields: [
              { name: "👤 User", value: `\`${data.username}\` (${data.userid})`, inline: true },
              { name: "⚙️ Executor", value: `\`${data.executor}\``, inline: true }
            ],
            timestamp: new Date().toISOString()
          }]
        })
      });
      return res.status(200).send('OK');
    } catch (e) { return res.status(500).send('Error'); }
  }

  // 2. THE SCRIPT (Using Base64 so it NEVER breaks)
  if (isRoblox) {
    res.setHeader('Content-Type', 'text/plain');
    
    // --- YOUR BASE64 GOES BELOW ---
    const MY_SCRIPT_BASE64 = "";
    // ------------------------------

    const decodedScript = Buffer.from(MY_SCRIPT_BASE64, 'base64').toString('utf-8');
    return res.status(200).send(decodedScript);
  }

  // 3. THE WEBSITE (For Browsers)
  res.setHeader('Content-Type', 'text/html');
  return res.status(200).send(`
    <html>
      <head><title>HOUR HUB | Midnight Aurora</title></head>
      <body style="background:#06070e;color:#5B8CFF;font-family:sans-serif;display:flex;align-items:center;justify-content:center;height:100vh;margin:0;">
        <div style="text-align:center;border:1px solid #5B8CFF;padding:50px;border-radius:20px;background:rgba(91,140,255,0.02);">
          <h1 style="letter-spacing:10px;">HOUR HUB</h1>
          <p style="color:white;opacity:0.6;">v21.0 Midnight Aurora</p>
          <p style="color:white;margin-top:20px;">ACCESS DENIED: PLEASE USE LOADER IN-GAME</p>
        </div>
      </body>
    </html>
  `);
}
